  const [email, setEmail] = React.useState('');
  const [insurance, setInsurance] = React.useState('');
  const [isMinor, setIsMinor] = React.useState(false);
  const [guardian, setGuardian] = React.useState('');
  const [consent, setConsent] = React.useState(false);

  const handleSave = () => {
    const id = 'P-' + String(Math.floor(10000 + Math.random() * 90000));
    const p = { id, first, last, dob, phone, email, insurance_provider: insurance, is_minor: isMinor, guardian_name: guardian, consent_approved: consent, insurance, last_visit: 'New', status: 'active' };
    window.PATIENTS.push(p);
    onSave(p);
  };

