              <div className="drawer-title">Add a new patient</div>
              <div className="drawer-sub">Fill in patient details below.</div>
            </div>
          </div>
          <button className="drawer-x" onClick={onClose}>&times;</button>
        </div>
        <div className="drawer-body">
          <div className="field-row">
            <div className="field"><label className="lbl">First name *</label><input className="d-input" value={first} onChange={e => setFirst(e.target.value)} /></div>
            <div className="field"><label className="lbl">Last name *</label><input className="d-input" value={last} onChange={e => setLast(e.target.value)} /></div>
          </div>
          <div className="field"><label className="lbl">Date of birth</label><input type="date" className="d-input" value={dob} onChange={e => setDob(e.target.value)} /></div>
          <div className="field-row">
            <div className="field"><label className="lbl">Phone</label><input className="d-input" value={phone} onChange={e => setPhone(e.target.value)} /></div>
            <div className="field"><label className="lbl">Email</label><input className="d-input" value={email} onChange={e => setEmail(e.target.value)} /></div>
          </div>
          <div className="field"><label className="lbl">Insurance provider</label><input className="d-input" value={insurance} onChange={e => setInsurance(e.target.value)} /></div>
          <div className="field" style={{ flexDirection: 'row', alignItems: 'center', gap: 8 }}>
            <input type="checkbox" id="isMinor" checked={isMinor} onChange={e => setIsMinor(e.target.checked)} />
            <label htmlFor="isMinor" className="lbl" style={{ marginBottom: 0 }}>Patient is a minor</label>
          </div>
          {isMinor && <div className="field"><label className="lbl">Guardian name</label><input className="d-input" value={guardian} onChange={e => setGuardian(e.target.value)} /></div>}
          <div className="field" style={{ flexDirection: 'row', alignItems: 'center', gap: 8 }}>
            <input type="checkbox" id="consent" checked={consent} onChange={e => setConsent(e.target.checked)} />
            <label htmlFor="consent" className="lbl" style={{ marginBottom: 0 }}>Consent approved</label>
          </div>
        </div>
        <div className="drawer-footer">
          <button className="btn btn-ghost btn-md" onClick={onClose}>Back</button>
          <button className="btn btn-primary btn-md" disabled={!first || !last} onClick={handleSave}>Save patient</button>
        </div>
      </aside>
    </>
  );
};

