const NewAppointmentDrawer = ({ onClose, onBook }) => {
  const [patient, setPatient] = React.useState(null);
  const [patientQ, setPatientQ] = React.useState('');
  const [patientFocus, setPatientFocus] = React.useState(false);
  const [provider, setProvider] = React.useState(null);
  const [providerQ, setProviderQ] = React.useState('');
  const [providerFocus, setProviderFocus] = React.useState(false);
  const [date, setDate] = React.useState('2026-05-04');
  const [time, setTime] = React.useState('09:00');
  const [showNewPatient, setShowNewPatient] = React.useState(false);

  React.useEffect(() => {
    const h = e => e.key === 'Escape' && onClose();
    document.addEventListener('keydown', h);
    return () => document.removeEventListener('keydown', h);
  }, [onClose]);

  const handleBook = () => {
    const name = patient ? patient.first + ' ' + patient.last : 'Unknown';
    onBook(name + ' \u00b7 ' + date + ' \u00b7 ' + time);
  };

  if (showNewPatient) return <NewPatientDrawer onClose={() => setShowNewPatient(false)} onSave={(p) => { setPatient(p); setPatientQ(p.first + ' ' + p.last); setShowNewPatient(false); }} />;

  const filteredPatients = window.PATIENTS.filter(p => !patientQ || (p.first + ' ' + p.last).toLowerCase().includes(patientQ.toLowerCase()));
  const filteredProviders = PROVIDERS.filter(p => !providerQ || p.name.toLowerCase().includes(providerQ.toLowerCase()));

  return (
    <>
      <div className="drawer-overlay" onClick={onClose} />
      <aside className="drawer" role="dialog">
        <div className="drawer-header">
          <div>
            <div className="drawer-meta">New appointment</div>
            <div className="drawer-title">Book a new appointment</div>
            <div className="drawer-sub">Select patient, provider, and slot.</div>
          </div>
          <button className="drawer-x" onClick={onClose}>&times;</button>
        </div>
        <div className="drawer-body">
          <div className="field">
            <div className="field-label-row">
              <label className="lbl">Patient</label>
              <a className="field-link" onClick={() => setShowNewPatient(true)}>+ New patient</a>
            </div>
            <div className="search-select">
              <input className="d-input" placeholder="Search patients..." value={patientQ} onChange={e => { setPatientQ(e.target.value); setPatient(null); }} onFocus={() => setPatientFocus(true)} onBlur={() => setTimeout(() => setPatientFocus(false), 150)} />
              {patientFocus && filteredPatients.length > 0 && (
                <div className="search-results">
                  {filteredPatients.slice(0, 8).map(p => (
                    <div key={p.id} className={'search-opt' + (patient && patient.id === p.id ? ' selected' : '')} onMouseDown={() => { setPatient(p); setPatientQ(p.first + ' ' + p.last); setPatientFocus(false); }}>
                      <span className="search-ava">{(p.first[0] + p.last[0]).toUpperCase()}</span>
                      {p.first} {p.last}
                      <span className="search-sub">{p.id}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
          <div className="field">
            <label className="lbl">Provider</label>
            <div className="search-select">
              <input className="d-input" placeholder="Search providers..." value={providerQ} onChange={e => { setProviderQ(e.target.value); setProvider(null); }} onFocus={() => setProviderFocus(true)} onBlur={() => setTimeout(() => setProviderFocus(false), 150)} />
              {providerFocus && filteredProviders.length > 0 && (
                <div className="search-results">
                  {filteredProviders.map(p => (
                    <div key={p.id} className={'search-opt' + (provider && provider.id === p.id ? ' selected' : '')} onMouseDown={() => { setProvider(p); setProviderQ(p.name); setProviderFocus(false); }}>
                      <span className="search-ava">{p.name.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase()}</span>
                      {p.name}
                      <span className="search-sub">{p.op}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
          <div className="field">
            <label className="lbl">Procedure</label>
            <select className="d-input" defaultValue="recall">
              <option value="recall">Recall &middot; 6mo (30 min)</option>
              <option value="crown-prep">Crown prep (60 min)</option>
              <option value="hygiene">Hygiene &middot; scaling (30 min)</option>
              <option value="implant">Implant follow-up (90 min)</option>
              <option value="composite">Composite &middot; MOD (60 min)</option>
              <option value="consult">New patient consult (30 min)</option>
              <option value="reline">Denture relines (45 min)</option>
              <option value="crown-seat">Crown seat (45 min)</option>
            </select>
          </div>
          <div className="field-row">
            <div className="field">
              <label className="lbl">Date</label>
              <input type="date" className="d-input" value={date} onChange={e => setDate(e.target.value)} />
            </div>
            <div className="field">
              <label className="lbl">Time</label>
              <input type="time" className="d-input" value={time} onChange={e => setTime(e.target.value)} />
            </div>
          </div>
          <div className="field">
            <label className="lbl">Duration</label>
            <select className="d-input" defaultValue="60">
              <option value="30">30 min</option>
              <option value="45">45 min</option>
              <option value="60">60 min</option>
              <option value="90">90 min</option>
            </select>
          </div>
          <div className="field">
            <label className="lbl">Notes</label>
            <textarea className="d-textarea" placeholder="Reason for visit, special instructions..." />
          </div>
        </div>
        <div className="drawer-footer">
          <button className="btn btn-ghost btn-md" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary btn-md" onClick={handleBook}>Book appointment</button>
        </div>
      </aside>
    </>
  );
};

