              <input className="d-input" placeholder="Search providers..." value={providerQ} onChange={e => { setProviderQ(e.target.value); setProvider(null); }} onFocus={() => setProviderFocus(true)} onBlur={() => setTimeout(() => setProviderFocus(false), 150)} />
              {providerFocus && filteredProviders.length > 0 && (
                <div className="search-results">
                  {filteredProviders.map(p => (
                    <div key={p.id} className={'search-opt' + (provider && provider.id === p.id ? ' selected' : '')} onMouseDown={() => { setProvider(p); setProviderQ(p.name); setProviderFocus(false); }}>
                      <span className="search-ava">{p.name.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase()}</span>
                      {p.name}
                      <span className="search-sub">{p.op}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
          <div className="field">
            <label className="lbl">Procedure</label>
            <select className="d-input" defaultValue="recall">
              <option value="recall">Recall &middot; 6mo (30 min)</option>
              <option value="crown-prep">Crown prep (60 min)</option>
              <option value="hygiene">Hygiene &middot; scaling (30 min)</option>
              <option value="implant">Implant follow-up (90 min)</option>
              <option value="composite">Composite &middot; MOD (60 min)</option>
              <option value="consult">New patient consult (30 min)</option>
              <option value="reline">Denture relines (45 min)</option>
              <option value="crown-seat">Crown seat (45 min)</option>
            </select>
          </div>
          <div className="field-row">
            <div className="field">
              <label className="lbl">Date</label>
              <input type="date" className="d-input" value={date} onChange={e => setDate(e.target.value)} />
            </div>
            <div className="field">
              <label className="lbl">Time</label>
              <input type="time" className="d-input" value={time} onChange={e => setTime(e.target.value)} />
            </div>
          </div>
          <div className="field">
            <label className="lbl">Duration</label>
            <select className="d-input" defaultValue="60">
              <option value="30">30 min</option>
              <option value="45">45 min</option>
              <option value="60">60 min</option>
              <option value="90">90 min</option>
            </select>
          </div>
          <div className="field">
            <label className="lbl">Notes</label>
            <textarea className="d-textarea" placeholder="Reason for visit, special instructions..." />
          </div>
        </div>
        <div className="drawer-footer">
          <button className="btn btn-ghost btn-md" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary btn-md" onClick={handleBook}>Book appointment</button>
        </div>
      </aside>
    </>
  );
};

