import { useQuery } from '@tanstack/react-query';
import { Link } from 'react-router-dom';
import { type ColumnDef } from '@tanstack/react-table';
import { DollarSign, UserX, FlaskConical, CreditCard, Calendar, FileText, Users } from 'lucide-react';
import { fetcher } from '../../api/client';
import { useAuthStore } from '../auth/store';
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardFooter,
} from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { PageHeader } from '@/components/ui/page-header';
import { DataTable } from '@/components/ui/data-table';

const fmt = new Intl.NumberFormat('en-CA', { style: 'currency', currency: 'CAD' });
const pct = (n: number) => `${(n * 100).toFixed(1)}%`;

interface KpiData {
  production_this_month: number;
  ar_aging: { bucket: string; amount: number }[];
  no_show_rate: number;
  lab_cost_per_case: number;
}

interface ProviderRow {
  provider_name: string;
  production: number;
}

interface LabRow {
  lab_name: string;
  total_cases: number;
  remake_rate: number;
}

interface ActivityRow {
  time: string;
  type: 'appointment' | 'invoice' | 'lead';
  description: string;
  status: string;
}

const providerColumns: ColumnDef<ProviderRow>[] = [
  { accessorKey: 'provider_name', header: 'Provider' },
  {
    accessorKey: 'production',
    header: 'Production',
    cell: ({ getValue }) => {
      const v = getValue<number>();
      return v ? fmt.format(v) : <span className="text-muted-foreground">—</span>;
    },
  },
];

const labColumns: ColumnDef<LabRow>[] = [
  { accessorKey: 'lab_name', header: 'Lab' },
  { accessorKey: 'total_cases', header: 'Cases' },
  {
    accessorKey: 'remake_rate',
    header: 'Remake Rate',
    cell: ({ getValue }) => pct(getValue<number>()),
  },
];

const activityColumns: ColumnDef<ActivityRow>[] = [
  { accessorKey: 'time', header: 'Time' },
  {
    accessorKey: 'type',
    header: 'Type',
    cell: ({ getValue }) => {
      const t = getValue<string>();
      const Icon = t === 'appointment' ? Calendar : t === 'invoice' ? FileText : Users;
      return <Icon className="h-4 w-4 text-muted-foreground" />;
    },
  },
  { accessorKey: 'description', header: 'Description' },
  {
    accessorKey: 'status',
    header: 'Status',
    cell: ({ getValue }) => <Badge variant="secondary">{getValue<string>()}</Badge>,
  },
];

export default function Dashboard() {
  const clinicId = useAuthStore((s) => s.clinicId);
  const lastUpdated = new Date().toLocaleTimeString();

  const { data: kpi } = useQuery<KpiData>({
    queryKey: ['reporting', 'kpi', clinicId],
    queryFn: () => fetcher<KpiData>('/api/v2/reporting/kpi'),
  });

  const { data: byProvider = [] } = useQuery<ProviderRow[]>({
    queryKey: ['reporting', 'by-provider', clinicId],
    queryFn: () => fetcher<ProviderRow[]>('/api/v2/reporting/production-by-provider'),
  });

  const { data: labRates = [] } = useQuery<LabRow[]>({
    queryKey: ['reporting', 'lab-remake', clinicId],
    queryFn: () => fetcher<LabRow[]>('/api/v2/reporting/remake-rate-by-lab'),
  });

  const { data: appointments = [] } = useQuery<{ id: string; start_time: string; patient_name?: string; status: string }[]>({
    queryKey: ['appointments', 'today', clinicId],
    queryFn: () => fetcher('/api/appointments?today=true'),
  });

  const { data: invoices = [] } = useQuery<{ id: string; created_at: string; patient_name?: string; status: string }[]>({
    queryKey: ['invoices', 'recent', clinicId],
    queryFn: () => fetcher('/api/v2/billing/invoices?days=7'),
  });

  const { data: leads = [] } = useQuery<{ id: string; created_at: string; name?: string; status: string }[]>({
    queryKey: ['leads', 'recent', clinicId],
    queryFn: () => fetcher('/api/leads?days=7'),
  });

  const AR_BUCKETS = kpi?.ar_aging ?? [
    { bucket: '0–30', amount: 0 },
    { bucket: '31–60', amount: 0 },
    { bucket: '61–90', amount: 0 },
    { bucket: '90+', amount: 0 },
  ];

  const activityRows: ActivityRow[] = [
    ...appointments.map((a) => ({
      time: new Date(a.start_time).toLocaleTimeString(),
      type: 'appointment' as const,
      description: a.patient_name ?? 'Appointment',
      status: a.status,
    })),
    ...invoices.map((i) => ({
      time: new Date(i.created_at).toLocaleTimeString(),
      type: 'invoice' as const,
      description: i.patient_name ?? 'Invoice',
      status: i.status,
    })),
    ...leads.map((l) => ({
      time: new Date(l.created_at).toLocaleTimeString(),
      type: 'lead' as const,
      description: l.name ?? 'Lead',
      status: l.status,
    })),
  ]
    .sort((a, b) => b.time.localeCompare(a.time))
    .slice(0, 10);

  return (
    <div className="space-y-6">
      <PageHeader
        title="Dashboard"
        description={`Last updated ${lastUpdated}`}
        actions={
          <>
            <Button variant="outline">Date range</Button>
            <Button onClick={() => {}}>Export</Button>
          </>
        }
      />

      {/* KPI tiles */}
      <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card data-testid="kpi-tile">
          <CardHeader className="flex flex-row items-center justify-between pb-2">
            <span className="text-sm text-muted-foreground">Production this month</span>
            <DollarSign className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-semibold">
              {kpi ? fmt.format(kpi.production_this_month) : <span className="text-muted-foreground">—</span>}
            </div>
          </CardContent>
          <CardFooter>
            <Badge variant="success">+12%</Badge>
          </CardFooter>
        </Card>

        <Card data-testid="kpi-tile">
          <CardHeader className="flex flex-row items-center justify-between pb-2">
            <span className="text-sm text-muted-foreground">No-show rate</span>
            <UserX className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-semibold">
              {kpi ? pct(kpi.no_show_rate) : <span className="text-muted-foreground">—</span>}
            </div>
          </CardContent>
          <CardFooter>
            <Badge variant="destructive">+0.4%</Badge>
          </CardFooter>
        </Card>

        <Card data-testid="kpi-tile">
          <CardHeader className="flex flex-row items-center justify-between pb-2">
            <span className="text-sm text-muted-foreground">Lab cost / case</span>
            <FlaskConical className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-semibold">
              {kpi ? fmt.format(kpi.lab_cost_per_case) : <span className="text-muted-foreground">—</span>}
            </div>
          </CardContent>
          <CardFooter>
            <Badge variant="secondary">—</Badge>
          </CardFooter>
        </Card>

        <Card data-testid="kpi-tile">
          <CardHeader className="flex flex-row items-center justify-between pb-2">
            <span className="text-sm text-muted-foreground">A/R balance</span>
            <CreditCard className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-semibold">
              {kpi
                ? fmt.format(AR_BUCKETS.reduce((s, b) => s + b.amount, 0))
                : <span className="text-muted-foreground">—</span>}
            </div>
          </CardContent>
          <CardFooter>
            <Badge variant="secondary">—</Badge>
          </CardFooter>
        </Card>
      </div>

      {/* A/R Aging */}
      <Card>
        <CardHeader className="flex flex-row items-center justify-between">
          <CardTitle>A/R Aging</CardTitle>
          <Button variant="link" asChild>
            <Link to="/billing?status=overdue">View overdue invoices</Link>
          </Button>
        </CardHeader>
        <CardContent>
          <div className="flex gap-4">
            {AR_BUCKETS.map((b) => (
              <div key={b.bucket} className="flex-1 rounded-lg border p-3 text-center">
                <div className="text-xs text-muted-foreground">{b.bucket} days</div>
                <div className="mt-1 font-semibold">
                  {b.amount ? fmt.format(b.amount) : <span className="text-muted-foreground">—</span>}
                </div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Production by Provider + Remake Rate by Lab */}
      <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
        <Card>
          <CardHeader>
            <CardTitle>Production by Provider</CardTitle>
          </CardHeader>
          <CardContent>
            {byProvider.length > 0 ? (
              <DataTable data-testid="provider-table" columns={providerColumns} data={byProvider} />
            ) : (
              <div className="flex flex-col items-center gap-2 py-8 text-center">
                <DollarSign className="h-8 w-8 text-muted-foreground" />
                <p className="text-sm text-muted-foreground">No data yet</p>
              </div>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Remake Rate by Lab</CardTitle>
          </CardHeader>
          <CardContent>
            {labRates.length > 0 ? (
              <DataTable data-testid="lab-table" columns={labColumns} data={labRates} />
            ) : (
              <div className="flex flex-col items-center gap-2 py-8 text-center">
                <FlaskConical className="h-8 w-8 text-muted-foreground" />
                <p className="text-sm text-muted-foreground">No data yet</p>
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Recent activity */}
      <Card>
        <CardHeader>
          <CardTitle>Recent activity</CardTitle>
        </CardHeader>
        <CardContent>
          {activityRows.length > 0 ? (
            <DataTable columns={activityColumns} data={activityRows} />
          ) : (
            <div className="flex flex-col items-center gap-2 py-8 text-center">
              <Calendar className="h-8 w-8 text-muted-foreground" />
              <p className="text-sm text-muted-foreground">No data yet</p>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

// AppointmentCard.jsx — Today's appointment row (time · patient · provider · status)

const STATUS_TONE = {
  confirmed: { bg: '#E8F5EE', fg: '#2A7D4F', label: 'Confirmed' },
  pending:   { bg: '#FDF3E5', fg: '#B45309', label: 'Pending'   },
  no_show:   { bg: '#F8E5E8', fg: '#9B2335', label: 'No-show'   },
  completed: { bg: '#F5F2EC', fg: '#4A5568', label: 'Completed' },
};

const AppointmentCard = ({ appointment, onClick }) => {
  const a = appointment;
  const tone = STATUS_TONE[a.status] || STATUS_TONE.confirmed;
  const initials = a.patient.split(' ').map(s => s[0]).slice(0, 2).join('');
  return (
    <div style={{
      background: '#fff', border: '1px solid #EDE9E0', borderRadius: 6,
      padding: '14px 16px', display: 'grid',
      gridTemplateColumns: '64px 32px 1fr auto', gap: 14, alignItems: 'center',
      transition: 'box-shadow 200ms ease', cursor: 'pointer',
    }}
    onClick={onClick}
    onMouseEnter={e => { e.currentTarget.style.boxShadow = '0 2px 8px rgba(10,25,47,0.08)'; }}
    onMouseLeave={e => { e.currentTarget.style.boxShadow = 'none'; }}>
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-start' }}>
        <span style={{ fontFamily: "'JetBrains Mono', monospace", fontWeight: 600, fontSize: '1rem', color: '#0A192F' }}>{a.time}</span>
        <span style={{ fontFamily: "'Inter', sans-serif", fontSize: '0.7rem', color: '#8A9BB0' }}>{a.duration} min</span>
      </div>
      <div style={{ width: 32, height: 32, borderRadius: 999, background: '#3A7FBD', color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 600, fontSize: '0.7rem' }}>{initials.toUpperCase()}</div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 2, minWidth: 0 }}>
        <span style={{ fontFamily: "'Inter', sans-serif", fontWeight: 600, fontSize: '0.88rem', color: '#1C2333' }}>{a.patient}</span>
        <span style={{ fontFamily: "'Inter', sans-serif", fontSize: '0.74rem', color: '#4A5568' }}>{a.kind} · {a.provider} · Op {a.chair}</span>
      </div>
      <span style={{ fontSize: '0.66rem', fontWeight: 600, padding: '3px 10px', borderRadius: 4, letterSpacing: '0.06em', textTransform: 'uppercase', background: tone.bg, color: tone.fg }}>{tone.label}</span>
    </div>
  );
};

Object.assign(window, { AppointmentCard });

import { useRef, useState, useEffect } from 'react';
import FullCalendar from '@fullcalendar/react';
import timeGridPlugin from '@fullcalendar/timegrid';
import dayGridPlugin from '@fullcalendar/daygrid';
import interactionPlugin from '@fullcalendar/interaction';
import type { DateSelectArg, EventDropArg } from '@fullcalendar/core';
import type { EventClickArg, EventInput } from '@fullcalendar/core';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { fetcher } from '../../api/client';
import { useAuthStore } from '../auth/store';
import AppointmentDrawer from './AppointmentDrawer';
import NewAppointmentDialog from './NewAppointmentDialog';
import { PageHeader } from '@/components/ui/page-header';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent } from '@/components/ui/card';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Select,
  SelectTrigger,
  SelectValue,
  SelectContent,
  SelectItem,
} from '@/components/ui/select';
import './scheduler.css';

interface CalEvent {
  id: string;
  title: string;
  start: string;
  end: string;
  patient_id?: string;
  status?: string;
}

interface Doctor {
  id: number;
  name: string;
}

interface Service {
  id: number;
  name: string;
}

interface Patient {
  id: string;
  first_name: string;
  last_name: string;
}

const STATUS_COLORS: Record<string, string> = {
  scheduled: 'bg-blue-100 text-blue-800',
  confirmed: 'bg-green-100 text-green-800',
  completed: 'bg-zinc-100 text-zinc-800',
  cancelled: 'bg-red-100 text-red-800',
  'no-show': 'bg-amber-100 text-amber-800',
};

function getWeekRange(): string {
  const now = new Date();
  const start = new Date(now);
  start.setDate(now.getDate() - now.getDay());
  const end = new Date(start);
  end.setDate(start.getDate() + 6);
  return `${start.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – ${end.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}`;
}

export default function Scheduler() {
  const clinicId = useAuthStore((s) => s.clinicId);
  const qc = useQueryClient();
  const calRef = useRef<FullCalendar>(null);

  const [drawerApptId, setDrawerApptId] = useState<string | null>(null);
  const [newApptRange, setNewApptRange] = useState<{ start: string; end: string } | null>(null);
  const [providerFilter, setProviderFilter] = useState('all');
  const [serviceFilter, setServiceFilter] = useState('all');
  const [activeView, setActiveView] = useState<'Day' | 'Week' | 'Month'>('Week');

  const { data: events = [] } = useQuery<CalEvent[]>({
    queryKey: ['calendar-events', clinicId],
    queryFn: () => {
      const now = new Date();
      const start = new Date(now);
      start.setDate(now.getDate() - 7);
      const end = new Date(now);
      end.setDate(now.getDate() + 30);
      return fetcher<CalEvent[]>(
        `/api/calendar/events?start=${start.toISOString()}&end=${end.toISOString()}`,
      );
    },
  });

  const { data: doctors = [] } = useQuery<Doctor[]>({
    queryKey: ['doctors', clinicId],
    queryFn: () => fetcher<Doctor[]>('/api/doctors'),
  });

  const { data: services = [] } = useQuery<Service[]>({
    queryKey: ['services', clinicId],
    queryFn: () => fetcher<Service[]>('/api/services'),
  });

  // Bulk-resolve patient names to avoid N+1
  const patientIds = [...new Set(events.map((e) => e.patient_id).filter(Boolean))] as string[];
  const { data: patientsData } = useQuery<{ items: Patient[] }>({
    queryKey: ['patients-by-ids', patientIds],
    queryFn: () =>
      patientIds.length > 0
        ? fetcher<{ items: Patient[] }>(`/api/patients?ids=${patientIds.join(',')}`)
        : Promise.resolve({ items: [] }),
    enabled: patientIds.length > 0,
  });

  const patientMap = new Map<string, Patient>(
    (patientsData?.items ?? []).map((p) => [p.id, p]),
  );

  const reschedule = useMutation({
    mutationFn: ({ id, start, end }: { id: string; start: string; end: string }) =>
      fetcher(`/api/appointments/${id}/reschedule`, {
        method: 'PUT',
        body: JSON.stringify({ start_time: start, end_time: end }),
      }),
    onSuccess: () => qc.invalidateQueries({ queryKey: ['calendar-events', clinicId] }),
  });

  function handleSelect(arg: DateSelectArg) {
    setNewApptRange({ start: arg.startStr, end: arg.endStr });
  }

  function handleEventClick(arg: EventClickArg) {
    setDrawerApptId(arg.event.id);
  }

  function handleEventDrop(arg: EventDropArg) {
    const { event } = arg;
    reschedule.mutate({
      id: event.id,
      start: event.startStr,
      end: event.endStr ?? event.startStr,
    });
  }

  function handleViewChange(view: 'Day' | 'Week' | 'Month') {
    setActiveView(view);
    const viewMap = { Day: 'timeGridDay', Week: 'timeGridWeek', Month: 'dayGridMonth' } as const;
    const targetView = viewMap[view];
    // Notify test hooks
    const win = window as unknown as Record<string, ((v: string) => void) | undefined>;
    win['__onViewChange']?.(targetView);
    // Call FullCalendar API
    const calApi = calRef.current?.getApi();
    if (calApi) {
      calApi.changeView(targetView);
    } else {
      const fc = (window as unknown as Record<string, { changeView: (v: string) => void } | undefined>)['__fc'];
      fc?.changeView(targetView);
    }
  }

  const fcEvents: EventInput[] = events.map((e) => {
    const patient = e.patient_id ? patientMap.get(e.patient_id) : undefined;
    const patientName = patient ? `${patient.first_name} ${patient.last_name}` : '';
    const title = patientName ? `${patientName} — ${e.title}` : e.title;
    return {
      id: e.id,
      title,
      start: e.start,
      end: e.end,
      extendedProps: { status: e.status ?? 'scheduled', patientName },
    };
  });

  useEffect(() => {
    if (typeof window !== 'undefined' && calRef.current) {
      const api = calRef.current.getApi();
      if (api) {
        (window as unknown as Record<string, unknown>)['__fc'] = api;
      }
    }
  });

  return (
    <div className="flex flex-col gap-4 p-6">
      <PageHeader
        title="Schedule"
        description={getWeekRange()}
        actions={
          <>
            <Button
              variant="outline"
              onClick={() => {
                const api = calRef.current?.getApi();
                api?.today();
              }}
            >
              Today
            </Button>
            <Button
              onClick={() => {
                const now = new Date();
                const end = new Date(now.getTime() + 30 * 60 * 1000);
                setNewApptRange({ start: now.toISOString(), end: end.toISOString() });
              }}
            >
              + New appointment
            </Button>
          </>
        }
      />

      {/* Toolbar Card */}
      <Card>
        <CardContent className="flex items-center gap-3 py-3">
          {/* Provider filter */}
          <Select value={providerFilter} onValueChange={setProviderFilter}>
            <SelectTrigger className="w-44" data-testid="provider-filter">
              <SelectValue placeholder="All providers" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All providers</SelectItem>
              {doctors.map((d) => (
                <SelectItem key={d.id} value={String(d.id)}>
                  {d.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          {/* Service filter */}
          <Select value={serviceFilter} onValueChange={setServiceFilter}>
            <SelectTrigger className="w-44">
              <SelectValue placeholder="All services" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">All services</SelectItem>
              {services.map((s) => (
                <SelectItem key={s.id} value={String(s.id)}>
                  {s.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          {/* Status legend */}
          <div className="flex items-center gap-1.5">
            {Object.entries(STATUS_COLORS).map(([status, cls]) => (
              <Badge key={status} className={`text-xs capitalize ${cls}`} variant="outline">
                {status}
              </Badge>
            ))}
          </div>

          {/* View toggle — pushed to the right */}
          <div className="ml-auto">
            <Tabs value={activeView} onValueChange={(v) => handleViewChange(v as 'Day' | 'Week' | 'Month')}>
              <TabsList>
                <TabsTrigger value="Day">Day</TabsTrigger>
                <TabsTrigger value="Week">Week</TabsTrigger>
                <TabsTrigger value="Month">Month</TabsTrigger>
              </TabsList>
            </Tabs>
          </div>
        </CardContent>
      </Card>

      {/* Calendar Card */}
      <Card>
        <CardContent className="p-0">
          <FullCalendar
            ref={calRef}
            plugins={[timeGridPlugin, dayGridPlugin, interactionPlugin]}
            initialView="timeGridWeek"
            headerToolbar={false}
            slotDuration="00:15:00"
            selectable
            editable
            events={fcEvents}
            select={handleSelect}
            eventClick={handleEventClick}
            eventDrop={handleEventDrop}
            eventDidMount={(info) => {
              const status = info.event.extendedProps?.status as string | undefined;
              if (status) {
                info.el.setAttribute('data-status', status.toLowerCase().replace('_', ''));
              }
              const patientName = info.event.extendedProps?.patientName as string | undefined;
              const service = info.event.title;
              if (patientName) {
                info.el.setAttribute('title', `${patientName} · ${service} · ${status ?? ''}`);
              }
            }}
          />
        </CardContent>
      </Card>

      <AppointmentDrawer
        appointmentId={drawerApptId}
        open={!!drawerApptId}
        onClose={() => setDrawerApptId(null)}
        onChanged={() => qc.invalidateQueries({ queryKey: ['calendar-events', clinicId] })}
      />

      <NewAppointmentDialog
        key={newApptRange ? `${newApptRange.start}-${newApptRange.end}` : 'closed'}
        open={!!newApptRange}
        start={newApptRange?.start ?? ''}
        end={newApptRange?.end ?? ''}
        onClose={() => setNewApptRange(null)}
        onCreated={() => {
          setNewApptRange(null);
          qc.invalidateQueries({ queryKey: ['calendar-events', clinicId] });
        }}
      />
    </div>
  );
}

